+    fn required_capability(operation: &str) -> Option<CapabilityId> {
+        Some(match operation {
+            OP_ACCOUNT_WHOAMI | OP_HEALTH => CapabilityId::from_static(CAP_ACCOUNT_READ),
+            OP_DOCS_LIST | OP_DOCS_GET | OP_PAGES_LIST | OP_PAGES_GET => {
