+            && !config
+                .allowed_doc_ids
+                .iter()
+                .any(|allowed| allowed == doc_id)
+        {
+            return Err(FcpError::Unauthorized {
+                code: 2001,
+                message: format!("Doc {doc_id} is outside the configured allowlist"),
+            });
+        }
+        Ok(())
+    }
